local TpPenGroup = Tabs.Teleports:AddLeftGroupbox("Загон ")
TpPenGroup:AddButton({
    Text="→ Мой загон ",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pen = M.findMyPen()
        if pen then
            local pos = M.getPenBasePosition()
            if pos then root.CFrame=CFrame.new(pos) end
            Library:Notify({Title="Телепортировано ",Description="Загон №"..pen.Name.." ",Time=2})
        else
            Library:Notify({Title="Ошибка ",Description="Загон не найден! ",Time=2})
        end
    end,
})
TpPenGroup:AddButton({
    Text="→ Первый питомец в загоне ",
    Func=function()
        local root = game.Players.LocalPlayer.Character and game.Players.LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
        if not root then return end
        local pets = M.getMyPenPets()
        if #pets==0 then Library:Notify({Title="Загон ",Description="В загоне нет питомцев. ",Time=2}) return end
        local part = pets[1]:FindFirstChildWhichIsA("BasePart")
        if part then
            root.CFrame=CFrame.new(part.Position+Vector3.new(0,3,0))
            local info = {name=pets[1]:GetAttribute("Name") or pets[1].Name}
            Library:Notify({Title="Телепортировано ",Description=info.name.." ",Time=2})
        end
    end,
})

